void dummyStratumReceiveLoop(std::stop_token st, ConcurrentQueue<nlohmann::json>& queue, unsigned int timeBetweenJobsSec, unsigned int frequencyClearJobs)
{
    unsigned int currentDataIndex = 0;
    unsigned int clearJobsIndex = 0;

    while (!st.stop_requested())
    {
        nlohmann::json data = exampleData[currentDataIndex];

        // data["params"][8] is the clearJobQueue flag.
        if (frequencyClearJobs > 0)
        {
            data["params"][8] = clearJobsIndex == 0;
            clearJobsIndex = (clearJobsIndex + 1) % frequencyClearJobs;
        }
        else
            data["params"][8] = false;

        queue.push(std::move(data));
        currentDataIndex = (currentDataIndex + 1) % exampleData.size();

        // TODO: replace the loop below with condition_variable::wait_for(...) with the time and stop token.
        for (int s = 0; s < timeBetweenJobsSec && !st.stop_requested(); ++s) // check stop token to be able to react to request_stop() while "sleeping"
            std::this_thread::sleep_for(std::chrono::milliseconds(1000));
    }
}